SELECT

FROM sys_data_domain
WHERE code = #{code}
  AND tenant_id = #{tenantId}
  AND is_delete = 0
LIMIT 1

SELECT

FROM sys_data_domain

    is_delete = 0

        AND name LIKE CONCAT('%', #{name}, '%')


        AND code LIKE CONCAT('%', #{code}, '%')


        AND type = #{type}


        AND enabled = #{enabled}


        AND create_time <= #{createTime}


ORDER BY create_time DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(*)
FROM sys_data_domain

    is_delete = 0

        AND name LIKE CONCAT('%', #{name}, '%')


        AND code LIKE CONCAT('%', #{code}, '%')


        AND type = #{type}


        AND enabled = #{enabled}


        AND create_time <= #{createTime}
